/**
 * HomeView.js
 * The Landing/Home view component.
 *
 * Responsibilities:
 * 1. Fetches the latest articles list from `/index.json` (generated by Hugo) on mount.
 * 2. Displays <v-skeleton-loader> for a better UX during data fetching.
 * 3. Renders article cards using Vuetify's <v-card> after data is retrieved.
 * 4. Ensures all links use <router-link> or programmatic navigation for SPA behavior.
 */
const { onMounted } = Vue;
import { t } from '../i18n.js';
import StateFeedback from '../components/StateFeedback.js';
import PostCard from '../components/PostCard.js';
import AnimatedList from '../components/AnimatedList.js';
import PaginationControl from '../components/PaginationControl.js';
import { useHome } from '../composables/useHome.js';

export default {
  components: {
    StateFeedback,
    PostCard,
    AnimatedList,
    PaginationControl
  },
  template: `
    <v-container max-width="1000">
      <!-- Hero Banner - Dynamically injected from Hugo partials -->
      <component :is="'custom-home-banner'" :siteConfig="siteConfig"></component>

      <v-row class="mb-6 align-center">
        <v-col class="px-8">
          <h2 class="text-h4 font-weight-bold text-primary">
            <v-icon class="mr-2">mdi-newspaper-variant-outline</v-icon>
            {{ t('home.latestArticles') }}
          </h2>
        </v-col>
      </v-row>

      <!-- Loading: Show skeleton loader cards -->
      <state-feedback :loading="loading" :error="error" skeleton-type="cards"></state-feedback>

      <!-- Loaded: Show articles list in Modern List Feed -->
      <template v-if="!loading">
        <v-row>
          <v-col class="px-8">
            <animated-list :items="paginatedPosts">
              <template #default="{ item }">
                <post-card :item="item"></post-card>
              </template>
            </animated-list>

            <!-- Pagination Control -->
            <pagination-control
              v-model="currentPage"
              :total-pages="totalPages"
              @change="scrollToTop"
            ></pagination-control>
          </v-col>
        </v-row>
      </template>

    </v-container>
  `,
  setup() {
    const {
      paginatedPosts,
      loading,
      error,
      currentPage,
      totalPages,
      scrollToTop,
      siteConfig
    } = useHome();

    onMounted(() => {
      // document.title is handled by useHome composable
    });

    return {
      paginatedPosts, loading, error, currentPage, totalPages, scrollToTop, t,
      siteConfig
    };
  }
};
